css:
.loader {color: var(--loader-color, #dc2626);
  --loader-secondary-color: #f97316;
  --loader-bg: #ffffff;
   width: 30px;
   aspect-ratio: 1;
   background: var(--loader-color, #dc2626);
   display: grid;
   animation: l4-0 1s infinite linear;
}
.loader::before, .loader::after  {
  content: "";
   grid-area: 1/1;
   background:var(--loader-color, #dc2626);
   animation: inherit;
   animation-name: l4-1;
}
.loader::after  {
  background: var(--loader-color, #dc2626);
   --s: 60deg;
}
@keyframes l4-0  {
  0%,20% {transform: rotate(0)}
100% {transform: rotate(90deg)}
}
@keyframes l4-1  {
  50% {transform: rotate(var(--s,30deg))}
100% {transform: rotate(0)}
}
